body.script:
// Wait for all scripts and the DOM to be fully loaded
window.addEventListener('load', async () => {
    // 1. Initialize Bare-Mux Transport
    if ('BareMux' in window) {
        const mux = new BareMux.BareMuxConnection('/baremux.js');

        // Initialize CurlTransport using libcurl.js and Wisp
        const transport = new BareMux.CurlTransport('wss://wisp.mercurywork.shop');
        await mux.setTransport(transport);
    } else {
        console.error("BareMux is not defined");
    }

    // 2. Set UV Window Config Variables
    if (window.__uv$config) {
        // Ensure the wisp server is reflected in config if applicable, 
        // though CurlTransport handles the transport itself.
        window.__uv$config.wisp = 'wss://wisp.mercurywork.shop';
    }

    // 3. Handle Navigation from the URL Input Box
    const input = document.getElementById('url-input');
    input.addEventListener('keypress', (event) => {
        if (event.key === 'Enter') {
            const url = input.value.trim();
            if (!url) return;

            // Fallback to Ultraviolet encoding logic
            if (window.__uv$config && window.__uv$origin && window.__uv$location) {
                const mappedUrl = window.__uv$config.prefix + window.__uv$config.encodeUrl(url);
                // Navigate to the Ultraviolet proxied URL
                window.location.href = mappedUrl;
            } else {
                // Default fallback navigation
                console.warn("Ultraviolet config not fully loaded yet.");
            }
        }
    });
});
